import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface Variant {
  name: string;
  conversionRate: number;
  lift: number;
  confidence: number;
}

interface ABTestData {
  testName: string;
  variants: Variant[];
}

export default function Widget() {
  const abTestData = response.data as ABTestData;
  const { testName, variants } = abTestData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#212121', color: '#FFFFFF' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722' }}>
              {testName}
            </Typography>
            <Typography variant="body2" sx={{ mb: 1 }}>
              Test Variants
            </Typography>
            <Stack spacing={1}>
              {variants.map((variant) => (
                <Box key={variant.name} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <Typography variant="body2" sx={{ fontWeight: 600 }}>
                    {variant.name}
                  </Typography>
                  <Stack direction="row" spacing={0.5} alignItems="center">
                    {variant.lift >= 0 ? (
                      <TrendingUp sx={{ fontSize: 16, color: '#4CAF50' }} />
                    ) : (
                      <TrendingDown sx={{ fontSize: 16, color: '#F44336' }} />
                    )}
                    <Typography variant="body2">
                      {variant.conversionRate}% ({variant.lift}% lift)
                    </Typography>
                  </Stack>
                  <Chip label={`${variant.confidence}% Conf.`} sx={{ bgcolor: '#795548', color: '#FFFFFF', fontSize: '10px' }} />
                </Box>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <BarChart
              height={120}
              series={[
                {
                  data: variants.map(v => v.conversionRate),
                  color: '#FF5722',
                },
              ]}
              xAxis={[
                {
                  data: variants.map(v => v.name),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#E0E0E0',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
